import React, { useCallback, useMemo, useRef, useState } from 'react';
import { Layer, Stage } from 'react-konva';
import './App.css';
import Toolbar from './components/Toolbar';
import PenTool from './tools/PenTool';

const CANVAS_SIZE = 10000; // Large virtual canvas size

function App() {
  const [tool, setTool] = useState('pen');
  const [isDrawing, setIsDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const stageRef = useRef();
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [stageScale, setStageScale] = useState(1);
  const lastPointRef = useRef(null);
  const currentLineRef = useRef(null);

  // Get pointer position (works for both mouse and touch)
  const getPointerPosition = (e) => {
    const stage = e.target.getStage();
    return stage.getPointerPosition();
  };

  // Distance between two points
  const getDistance = (p1, p2) => {
    return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
  };

  // Filter points to maintain smooth curves and reduce noise
  const shouldAddPoint = useCallback((newPoint, lastPoint, minDistance = 2) => {
    if (!lastPoint) return true;
    return getDistance(newPoint, lastPoint) >= minDistance;
  }, []);

  // Smooth point interpolation for missing points during rapid movement
  const interpolatePoints = useCallback((p1, p2, steps = 3) => {
    const points = [];
    for (let i = 1; i < steps; i++) {
      const t = i / steps;
      points.push({
        x: p1.x + (p2.x - p1.x) * t,
        y: p1.y + (p2.y - p1.y) * t
      });
    }
    return points;
  }, []);

  const handlePointerDown = useCallback((e) => {
    if (tool === 'pen') {
      setIsDrawing(true);
      const pos = getPointerPosition(e);
      const adjustedPos = {
        x: (pos.x - stagePos.x) / stageScale,
        y: (pos.y - stagePos.y) / stageScale
      };

      lastPointRef.current = adjustedPos;

      // Create new line object
      const newLine = { 
        points: [adjustedPos.x, adjustedPos.y], 
        tool: 'pen',
        id: Date.now()
      };

      // Store reference to current line
      currentLineRef.current = newLine;

      // Add to lines array
      setLines(prevLines => [...prevLines, newLine]);
    }
  }, [tool, stagePos, stageScale]);

  const handlePointerMove = useCallback((e) => {
    if (!isDrawing || tool !== 'pen') return;

    // Safety check for currentLineRef
    if (!currentLineRef.current || !currentLineRef.current.points) {
      return;
    }

    const point = getPointerPosition(e);
    const adjustedPoint = {
      x: (point.x - stagePos.x) / stageScale,
      y: (point.y - stagePos.y) / stageScale
    };

    const lastPoint = lastPointRef.current;

    // Only add point if it's far enough from the last point
    if (shouldAddPoint(adjustedPoint, lastPoint, 1.5)) {
      // Create a copy of current points
      const currentPoints = [...currentLineRef.current.points];

      // If the distance is too large, interpolate points to fill gaps
      const distance = lastPoint ? getDistance(adjustedPoint, lastPoint) : 0;
      if (distance > 10 && lastPoint) {
        const interpolated = interpolatePoints(lastPoint, adjustedPoint, Math.ceil(distance / 5));
        interpolated.forEach(p => {
          currentPoints.push(p.x, p.y);
        });
      }

      currentPoints.push(adjustedPoint.x, adjustedPoint.y);
      lastPointRef.current = adjustedPoint;

      // Update current line reference with new points
      const updatedLine = {
        ...currentLineRef.current,
        points: currentPoints
      };
      currentLineRef.current = updatedLine;

      // Update the lines array
      setLines(prevLines => {
        const newLines = [...prevLines];
        const lastLineIndex = newLines.length - 1;
        if (lastLineIndex >= 0) {
          newLines[lastLineIndex] = updatedLine;
        }
        return newLines;
      });
    }
  }, [isDrawing, tool, stagePos, stageScale, shouldAddPoint, interpolatePoints]);

  const handlePointerUp = useCallback(() => {
    setIsDrawing(false);
    lastPointRef.current = null;
    // Don't set currentLineRef to null immediately, let it persist
    // currentLineRef.current = null;
  }, []);

  const handleWheel = useCallback((e) => {
    e.evt.preventDefault();

    const stage = stageRef.current;
    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const newScale = e.evt.deltaY > 0 ? oldScale * 0.9 : oldScale * 1.1;

    const newPos = {
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    };

    setStageScale(newScale);
    setStagePos(newPos);
  }, []);

  // Enhanced touch handling with better gesture recognition
  const handleTouchMove = useCallback((e) => {
    e.evt.preventDefault();

    if (e.evt.touches && e.evt.touches.length === 2) {
      // Pinch to zoom logic
      const touch1 = e.evt.touches[0];
      const touch2 = e.evt.touches[1];

      const dist = Math.sqrt(
        Math.pow(touch2.clientX - touch1.clientX, 2) +
        Math.pow(touch2.clientY - touch1.clientY, 2)
      );

      // Store initial distance for comparison
      if (!stageRef.current.lastDist) {
        stageRef.current.lastDist = dist;
        return;
      }

      const scale = stageScale * (dist / stageRef.current.lastDist);
      setStageScale(Math.max(0.1, Math.min(5, scale))); // Limit zoom range
      stageRef.current.lastDist = dist;
    } else {
      stageRef.current.lastDist = 0;
      handlePointerMove(e);
    }
  }, [handlePointerMove, stageScale]);

  // Memoize lines to prevent unnecessary re-renders
  const memoizedLines = useMemo(() => {
    return lines.map((line) => {
      // Safety check for line and points
      if (!line || !line.points || line.points.length < 2) {
        return null;
      }

      return (
        <PenTool
          key={line.id}
          points={line.points}
          strokeWidth={2}
          stroke="#000000"
        />
      );
    }).filter(Boolean); // Remove null entries
  }, [lines]);

  return (
    <div className="app">
      <Toolbar 
        activeTool={tool} 
        onToolChange={setTool}
      />
      <div className="canvas-container">
        <Stage
          ref={stageRef}
          width={window.innerWidth}
          height={window.innerHeight}
          onMouseDown={handlePointerDown}
          onMousemove={handlePointerMove}
          onMouseup={handlePointerUp}
          onTouchStart={handlePointerDown}
          onTouchMove={handleTouchMove}
          onTouchEnd={handlePointerUp}
          onWheel={handleWheel}
          scaleX={stageScale}
          scaleY={stageScale}
          x={stagePos.x}
          y={stagePos.y}
          draggable={tool === 'pan' || !isDrawing}
        >
          <Layer>
            {/* Grid background */}
            {/* We'll add grid later if needed */}

            {memoizedLines}
          </Layer>
        </Stage>
      </div>
    </div>
  );
}

export default App;
